struct ControlBlock {
    std::atomic<size_t> ref_count{1};

    void add_ref() { ++ref_count; }
    bool release() { return --ref_count == 0; }
};

MyClass& operator=(MyClass&& other) noexcept {
    if (this != &other) {
        cleanup();  // Release current resources
        ptr_ = other.ptr_;
        control_ = other.control_;
        other.ptr_ = nullptr;
        other.control_ = nullptr;
    }
    return *this;
}
